import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AlertCircle, ChevronLeft, ChevronRight, Play, RefreshCw, Send, ShieldAlert, Trash2, Loader2, BookMarked } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';
import { api } from '../api/client';
import { useLibrary } from '../context/LibraryContext';

const PLACEHOLDER = 'https://placehold.co/500x750/10130f/62a33c?text=Cap';
const fmt = id => (id ?? '').replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

export default function MangaDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { library, refreshLibrary } = useLibrary();

  const [detail, setDetail] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState(false);
  const [auditing, setAuditing] = useState(false);
  const [issues, setIssues] = useState([]);
  const [preparingTg, setPreparingTg] = useState(false);
  const [coverErr, setCoverErr] = useState(false);
  const [search, setSearch] = useState('');

  const manga = detail ?? library?.manga?.find(m => m.id === id);
  const cover = coverErr ? PLACEHOLDER : (manga?.cover_url ?? PLACEHOLDER);

  const chapters = useMemo(() =>
    manga ? [...manga.chapters].sort((a, b) => parseFloat(b.number ?? 0) - parseFloat(a.number ?? 0)) : [],
    [manga]
  );

  const filteredChapters = useMemo(() =>
    search.trim() ? chapters.filter(c => c.title?.toLowerCase().includes(search.toLowerCase()) || String(c.number).includes(search)) : chapters,
    [chapters, search]
  );

  useEffect(() => {
    let alive = true;
    setLoading(true);
    setError(null);
    api.getManga(id)
      .then(r => { if (alive) { setDetail(r.data); setError(null); } })
      .catch(err => { if (alive) { setDetail(null); setError(err); } })
      .finally(() => { if (alive) setLoading(false); });
    return () => { alive = false; };
  }, [id]);

  if (loading && !manga) return (
    <div className="flex items-center justify-center h-[60vh] flex-col gap-3">
      <Loader2 size={32} className="animate-spin text-brand-400" />
      <p className="text-sm text-[var(--color-text-muted)]">Carregando obra...</p>
    </div>
  );

  if (error) return (
    <div className="flex flex-col items-center justify-center h-[60vh] gap-3">
      <span className="text-5xl">⚠️</span>
      <p className="text-red-400 text-sm text-center px-8">Falha ao carregar a obra.</p>
    </div>
  );

  if (!manga) return (
    <div className="flex items-center justify-center h-[60vh]">
      <p className="text-[var(--color-text-muted)] text-sm">Obra não encontrada.</p>
    </div>
  );

  const handleDelete = async () => {
    if (!confirm(`Excluir "${manga.title}"?`)) return;
    setDeleting(true);
    try {
      await api.deleteManga(id);
      await refreshLibrary?.();
      navigate('/');
    } catch {
      alert('Erro ao excluir.');
      setDeleting(false);
    }
  };

  const handleAudit = async () => {
    setAuditing(true);
    try {
      const r = await api.auditManga(id);
      setIssues(r.data.discrepancies ?? []);
    } catch { setIssues([]); }
    finally { setAuditing(false); }
  };

  const handleTelegram = async () => {
    setPreparingTg(true);
    try {
      const r = await api.prepareMangaTelegram(id);
      await refreshLibrary?.();
      const d = await api.getManga(id); setDetail(d.data);
      alert(r.data.failed_pages?.length ? `Telegram preparado com ${r.data.failed_pages.length} falha(s).` : 'Pronto!');
    } catch { alert('Falha ao preparar para o Telegram.'); }
    finally { setPreparingTg(false); }
  };

  const firstChapter = chapters.length > 0 ? chapters[chapters.length - 1] : null;

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="relative">
      {/* Ambient blurred background */}
      <div
        className="fixed inset-0 opacity-10 pointer-events-none"
        style={{
          backgroundImage: `url(${cover})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: 'blur(60px)',
          zIndex: 0,
        }}
      />

      <div className="relative z-10">
        {/* Top bar */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-[var(--color-surface-border)]">
          <button
            onClick={() => navigate(-1)}
            className="flex items-center gap-2 text-sm text-[var(--color-text-secondary)] hover:text-white transition-colors"
          >
            <ChevronLeft size={18} /> Voltar
          </button>
          <button
            onClick={handleDelete}
            disabled={deleting}
            className="flex items-center gap-1.5 text-xs text-red-400 hover:text-red-300 transition-colors"
          >
            {deleting ? <RefreshCw size={13} className="animate-spin" /> : <Trash2 size={13} />}
            Excluir
          </button>
        </div>

        {/* Hero section */}
        <div className="flex gap-5 px-5 py-6 border-b border-[var(--color-surface-border)]">
          <motion.img
            src={cover}
            alt={manga.title}
            onError={() => setCoverErr(true)}
            className="w-28 rounded-xl shadow-2xl border border-[var(--color-surface-border)] shrink-0 object-cover"
            style={{ aspectRatio: '2/3' }}
            initial={{ opacity: 0, scale: 0.92 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ type: 'spring', stiffness: 300, damping: 25 }}
          />

          <motion.div
            className="flex flex-col justify-center gap-2"
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.05 }}
          >
            {manga.provider_id && (
              <span className="text-[10px] font-bold text-brand-400 uppercase tracking-widest">{fmt(manga.provider_id)}</span>
            )}
            <h1 className="text-xl font-black text-white leading-tight">{manga.title}</h1>
            <p className="text-sm text-[var(--color-text-muted)]">{chapters.length} capítulos</p>

            {/* Read button */}
            {firstChapter && (
              <motion.button
                className="flex items-center gap-2 bg-brand-500 hover:bg-brand-400 text-white text-sm font-bold px-4 py-2.5 rounded-xl transition-colors w-fit mt-1"
                whileTap={{ scale: 0.95 }}
                onClick={() => navigate(`/reader/${manga.id}/${firstChapter.id}`)}
              >
                <Play size={14} /> Ler do início
              </motion.button>
            )}
          </motion.div>
        </div>

        {/* Actions */}
        <div className="flex gap-2 px-4 py-3 border-b border-[var(--color-surface-border)] overflow-x-auto">
          <ActionButton
            icon={preparingTg ? <RefreshCw size={13} className="animate-spin" /> : <Send size={13} />}
            label="Telegram"
            onClick={handleTelegram}
            disabled={preparingTg || !chapters.length}
          />
          <ActionButton
            icon={auditing ? <RefreshCw size={13} className="animate-spin" /> : <ShieldAlert size={13} />}
            label="Auditar"
            onClick={handleAudit}
            disabled={auditing}
          />
          {issues.length > 0 && (
            <div className="flex items-center gap-2 px-3 py-2 rounded-xl bg-red-500/10 border border-red-500/20 text-xs text-red-400 shrink-0">
              <AlertCircle size={13} />
              {issues.length} capítulo(s) com problema
            </div>
          )}
        </div>

        {/* Chapter list */}
        <div className="px-4 py-4 pb-24">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider flex items-center gap-1.5">
              <BookMarked size={13} /> Capítulos
            </span>
            <span className="text-xs text-[var(--color-text-muted)]">{filteredChapters.length} de {chapters.length}</span>
          </div>

          {/* Search within chapters */}
          {chapters.length > 12 && (
            <input
              type="text"
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="Filtrar capítulo..."
              className="w-full mb-3 px-3 py-2 bg-[var(--color-surface)] border border-[var(--color-surface-border)] rounded-xl text-sm text-white placeholder:text-[var(--color-text-muted)] outline-none focus:border-brand-500/50 transition-colors"
            />
          )}

          <AnimatePresence initial={false}>
            <div className="space-y-1">
              {filteredChapters.map((ch, i) => {
                const hasIssue = issues.some(iss => iss.chapter_id === ch.id);
                return (
                  <motion.button
                    key={ch.id}
                    className="w-full flex items-center gap-3 px-3 py-3 rounded-xl hover:bg-[var(--color-surface-hover)] transition-colors text-left group"
                    whileTap={{ scale: 0.98 }}
                    initial={{ opacity: 0, y: 6 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: Math.min(i * 0.01, 0.3) }}
                    onClick={() => navigate(`/reader/${manga.id}/${ch.id}`)}
                  >
                    <span className="text-xs font-black text-brand-500 w-9 shrink-0 text-center">
                      {ch.number ?? '?'}
                    </span>
                    <span className="flex flex-col flex-1 min-w-0">
                      <span className="text-sm text-white line-clamp-1">{ch.title}</span>
                      <span className="text-[10px] text-[var(--color-text-muted)]">
                        {ch.page_count ?? ch.pages?.length ?? 0} páginas
                      </span>
                    </span>
                    {hasIssue
                      ? <AlertCircle size={15} className="text-red-400 shrink-0" />
                      : <Play size={14} className="text-[var(--color-text-muted)] group-hover:text-brand-400 transition-colors shrink-0" />
                    }
                  </motion.button>
                );
              })}
            </div>
          </AnimatePresence>

          {filteredChapters.length === 0 && (
            <p className="text-center text-sm text-[var(--color-text-muted)] py-8">Nenhum capítulo encontrado.</p>
          )}
        </div>
      </div>
    </motion.div>
  );
}

function ActionButton({ icon, label, onClick, disabled }) {
  return (
    <motion.button
      className="flex items-center gap-2 px-4 py-2 rounded-xl bg-[var(--color-surface)] border border-[var(--color-surface-border)] text-xs font-semibold text-[var(--color-text-secondary)] hover:text-white hover:border-brand-500/40 transition-colors disabled:opacity-50 shrink-0"
      whileTap={{ scale: 0.95 }}
      onClick={onClick}
      disabled={disabled}
    >
      {icon} {label}
    </motion.button>
  );
}

import React, { useEffect, useMemo, useRef, useState, useCallback } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { ChevronLeft, ChevronRight, Loader2, Maximize2, Minimize2, Settings } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';
import { useVirtualizer } from '@tanstack/react-virtual';
import { api } from '../api/client';
import { useReaderStore } from '../stores/useReaderStore';

export default function ReaderView() {
  const { mangaId, chapterId } = useParams();
  const navigate = useNavigate();
  const { saveProgress, zoomLevel, brightness } = useReaderStore();

  const [payload, setPayload] = useState(null);
  const [error, setError] = useState(null);
  const [hud, setHud] = useState(true);
  const [fullscreen, setFullscreen] = useState(false);

  const scrollRef = useRef(null);
  const hudTimer = useRef(null);

  // Lock body overscroll for native feel
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    document.body.style.overscrollBehavior = 'none';
    return () => {
      document.body.style.overflow = '';
      document.body.style.overscrollBehavior = '';
    };
  }, []);

  // Load chapter
  useEffect(() => {
    let alive = true;
    setPayload(null);
    setError(null);
    api.getReaderChapter(mangaId, chapterId)
      .then(r => { if (alive) setPayload(r.data); })
      .catch(err => { if (alive) setError(err); });
    return () => { alive = false; };
  }, [mangaId, chapterId]);

  // Save reading progress when payload is ready
  useEffect(() => {
    if (payload) {
      saveProgress(mangaId, chapterId, 0);
    }
  }, [payload, mangaId, chapterId, saveProgress]);

  // Keyboard nav
  useEffect(() => {
    const handler = e => {
      if (e.key === 'Escape') navigate(-1);
      if (e.key === 'ArrowLeft' && payload?.prev_chapter) navigate(`/reader/${mangaId}/${payload.prev_chapter.id}`);
      if (e.key === 'ArrowRight' && payload?.next_chapter) navigate(`/reader/${mangaId}/${payload.next_chapter.id}`);
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [navigate, mangaId, payload]);

  const chapter = payload?.chapter ?? null;
  const pages = useMemo(() => {
    if (!chapter || !payload?.pages?.length) return [];
    return payload.pages.map(p => api.getTelegramPageUrl(chapter.id, p.index));
  }, [chapter, payload]);

  // React Virtual for performance
  const rowVirtualizer = useVirtualizer({
    count: pages.length,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => window.innerWidth * 1.42, // Approx manga page ratio
    overscan: 3,
  });

  // HUD auto-hide on scroll
  const handleScroll = useCallback(() => {
    clearTimeout(hudTimer.current);
    setHud(true);
    hudTimer.current = setTimeout(() => setHud(false), 2800);
  }, []);

  const toggleHud = () => setHud(v => !v);

  // Navigation
  const goToChapter = (ch) => {
    if (!ch) return;
    navigate(`/reader/${mangaId}/${ch.id}`);
    scrollRef.current?.scrollTo({ top: 0, behavior: 'instant' });
  };

  // --- Loading state ---
  if (!payload && !error) return (
    <div className="fixed inset-0 bg-[var(--color-background)] flex items-center justify-center">
      <div className="flex flex-col items-center gap-3">
        <Loader2 size={28} className="animate-spin text-brand-400" />
        <p className="text-sm text-[var(--color-text-muted)]">Carregando capítulo...</p>
      </div>
    </div>
  );

  if (error) return (
    <div className="fixed inset-0 bg-[var(--color-background)] flex flex-col items-center justify-center gap-4">
      <span className="text-5xl">⚠️</span>
      <p className="text-red-400 text-sm text-center px-8">Falha ao carregar capítulo.</p>
      <button
        className="mt-2 px-5 py-2.5 rounded-xl bg-[var(--color-surface)] text-sm text-white hover:bg-[var(--color-surface-hover)] transition-colors"
        onClick={() => navigate(-1)}
      >
        Voltar
      </button>
    </div>
  );

  if (!chapter) return (
    <div className="fixed inset-0 bg-[var(--color-background)] flex items-center justify-center">
      <p className="text-[var(--color-text-muted)] text-sm">Capítulo não encontrado.</p>
    </div>
  );

  return (
    <div
      className="fixed inset-0 bg-black overflow-hidden"
      style={{ filter: brightness !== 100 ? `brightness(${brightness / 100})` : undefined }}
    >
      {/* Top HUD */}
      <AnimatePresence>
        {hud && (
          <motion.div
            className="absolute top-0 left-0 right-0 z-50 safe-pt"
            initial={{ opacity: 0, y: -44 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -44 }}
            transition={{ type: 'spring', stiffness: 380, damping: 30 }}
            onClick={e => e.stopPropagation()}
          >
            <div className="glass-elevated flex items-center gap-3 px-4 py-3 mx-3 mt-3 rounded-2xl">
              <button
                onClick={() => navigate(-1)}
                className="p-1.5 rounded-xl hover:bg-white/10 transition-colors"
                aria-label="Voltar"
              >
                <ChevronLeft size={20} className="text-white" />
              </button>

              <div className="flex-1 min-w-0">
                <p className="text-xs font-bold text-white truncate">{payload.manga_title}</p>
                <p className="text-[10px] text-[var(--color-text-muted)] truncate">{chapter.title}</p>
              </div>

              <button
                onClick={() => setFullscreen(v => !v)}
                className="p-1.5 rounded-xl hover:bg-white/10 transition-colors"
                aria-label="Fullscreen"
              >
                {fullscreen ? <Minimize2 size={17} className="text-white" /> : <Maximize2 size={17} className="text-white" />}
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Page scroll — Webtoon infinite vertical */}
      <div
        ref={scrollRef}
        className="absolute inset-0 overflow-y-auto overscroll-none"
        onScroll={handleScroll}
        onClick={toggleHud}
        style={{ scrollbarWidth: 'none' }}
      >
        <div
          style={{
            height: `${rowVirtualizer.getTotalSize()}px`,
            width: '100%',
            position: 'relative',
          }}
        >
          {rowVirtualizer.getVirtualItems().map(virtualItem => (
            <div
              key={virtualItem.key}
              style={{
                position: 'absolute',
                top: 0,
                left: 0,
                width: '100%',
                height: `${virtualItem.size}px`,
                transform: `translateY(${virtualItem.start}px)`,
              }}
            >
              <img
                src={pages[virtualItem.index]}
                alt={`Página ${virtualItem.index + 1}`}
                className="w-full h-full object-contain"
                style={{
                  maxWidth: fullscreen ? '100%' : `${zoomLevel}%`,
                  margin: '0 auto',
                  display: 'block',
                }}
                loading={virtualItem.index < 3 ? 'eager' : 'lazy'}
              />
            </div>
          ))}
        </div>

        {/* Chapter Navigation Footer (inside scroll at bottom) */}
        {pages.length > 0 && (
          <div
            className="flex items-center justify-between px-4 py-8 gap-4"
            onClick={e => e.stopPropagation()}
          >
            <motion.button
              className={`flex-1 flex items-center justify-center gap-2 py-3.5 rounded-2xl text-sm font-semibold transition-colors ${payload.prev_chapter ? 'bg-[var(--color-surface)] text-white hover:bg-[var(--color-surface-hover)]' : 'bg-[var(--color-surface)]/40 text-[var(--color-text-muted)] cursor-not-allowed'}`}
              whileTap={{ scale: payload.prev_chapter ? 0.96 : 1 }}
              disabled={!payload.prev_chapter}
              onClick={() => goToChapter(payload.prev_chapter)}
            >
              <ChevronLeft size={18} />
              Anterior
            </motion.button>

            <motion.button
              className={`flex-1 flex items-center justify-center gap-2 py-3.5 rounded-2xl text-sm font-semibold transition-colors ${payload.next_chapter ? 'bg-brand-500 text-white hover:bg-brand-400' : 'bg-[var(--color-surface)]/40 text-[var(--color-text-muted)] cursor-not-allowed'}`}
              whileTap={{ scale: payload.next_chapter ? 0.96 : 1 }}
              disabled={!payload.next_chapter}
              onClick={() => goToChapter(payload.next_chapter)}
            >
              Próximo
              <ChevronRight size={18} />
            </motion.button>
          </div>
        )}
      </div>

      {/* Bottom HUD (Progress) */}
      <AnimatePresence>
        {hud && (
          <motion.div
            className="absolute bottom-0 left-0 right-0 z-50 safe-pb"
            initial={{ opacity: 0, y: 44 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 44 }}
            transition={{ type: 'spring', stiffness: 380, damping: 30 }}
            onClick={e => e.stopPropagation()}
          >
            <div className="glass-elevated flex items-center gap-3 px-4 py-3 mx-3 mb-3 rounded-2xl">
              {/* Prev/Next quick buttons */}
              <button
                disabled={!payload.prev_chapter}
                onClick={() => goToChapter(payload.prev_chapter)}
                className="p-1.5 rounded-xl hover:bg-white/10 transition-colors disabled:opacity-40"
              >
                <ChevronLeft size={20} className="text-white" />
              </button>

              {/* Chapter indicator */}
              <div className="flex-1 text-center">
                <p className="text-xs font-semibold text-brand-400">
                  {chapter.number ? `Cap. ${chapter.number}` : chapter.title}
                </p>
                <p className="text-[10px] text-[var(--color-text-muted)]">
                  {pages.length} páginas
                </p>
              </div>

              <button
                disabled={!payload.next_chapter}
                onClick={() => goToChapter(payload.next_chapter)}
                className="p-1.5 rounded-xl hover:bg-white/10 transition-colors disabled:opacity-40"
              >
                <ChevronRight size={20} className="text-white" />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
